namespace sv_e238e250037c4fe1a2c34232344b2095.Auth;

// Serializable DTO used to persist auth state from server to WebAssembly client.
public sealed class UserInfo
{
    public required string Email { get; set; }
    public required string[] Roles { get; set; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Server;
using Microsoft.AspNetCore.Components.Web;

namespace sv_e238e250037c4fe1a2c34232344b2095.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that simulates a logged-in user
/// and persists the auth state so the WebAssembly client can pick it up.
/// </summary>
public sealed class ServerAuthenticationStateProvider : ServerAuthenticationStateProvider<UserInfo>
{
    private static readonly ClaimsPrincipal _user = CreateUser();

    private static ClaimsPrincipal CreateUser()
    {
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, "bob@example.com"),
            new(ClaimTypes.Email, "bob@example.com"),
            new(ClaimTypes.Role, "User"),
            new(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        return new ClaimsPrincipal(identity);
    }

    protected override Task<AuthenticationState> GetAuthenticationStateAsync(
        IComponentRenderMode? renderMode)
    {
        return Task.FromResult(new AuthenticationState(_user));
    }

    protected override UserInfo MapToSerialized(AuthenticationState authenticationState)
    {
        var principal = authenticationState.User;
        return new UserInfo
        {
            Email = principal.FindFirstValue(ClaimTypes.Email) ?? "",
            Roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray()
        };
    }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_e238e250037c4fe1a2c34232344b2095.Client.Auth;

/// <summary>
/// Client-side AuthenticationStateProvider that restores auth state
/// persisted by the server via PersistentComponentState.
/// </summary>
public sealed class ClientAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly AuthenticationState _unauthenticated =
        new(new ClaimsPrincipal(new ClaimsIdentity()));

    private readonly Task<AuthenticationState> _authStateTask;

    public ClientAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<UserInfo>(
                nameof(UserInfo), out var userInfo) && userInfo is not null)
        {
            _authStateTask = Task.FromResult(new AuthenticationState(CreateUser(userInfo)));
        }
        else
        {
            _authStateTask = Task.FromResult(_unauthenticated);
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authStateTask;

    private static ClaimsPrincipal CreateUser(UserInfo info)
    {
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, info.Email),
            new(ClaimTypes.Email, info.Email),
        };

        foreach (var role in info.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        var identity = new ClaimsIdentity(claims, authenticationType: "Persisted");
        return new ClaimsPrincipal(identity);
    }
}

// Matches the server-side DTO
public sealed class UserInfo
{
    public required string Email { get; set; }
    public required string[] Roles { get; set; }
}

