using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_e238e250037c4fe1a2c34232344b2095.Client.Auth;

/// <summary>
/// Client-side AuthenticationStateProvider that restores auth state
/// persisted by the server via PersistentComponentState.
/// </summary>
public sealed class ClientAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly AuthenticationState _unauthenticated =
        new(new ClaimsPrincipal(new ClaimsIdentity()));

    private readonly Task<AuthenticationState> _authStateTask;

    public ClientAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<UserInfo>(
                nameof(UserInfo), out var userInfo) && userInfo is not null)
        {
            _authStateTask = Task.FromResult(new AuthenticationState(CreateUser(userInfo)));
        }
        else
        {
            _authStateTask = Task.FromResult(_unauthenticated);
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authStateTask;

    private static ClaimsPrincipal CreateUser(UserInfo info)
    {
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, info.Email),
            new(ClaimTypes.Email, info.Email),
        };

        foreach (var role in info.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        var identity = new ClaimsIdentity(claims, authenticationType: "Persisted");
        return new ClaimsPrincipal(identity);
    }
}

// Matches the server-side DTO
public sealed class UserInfo
{
    public required string Email { get; set; }
    public required string[] Roles { get; set; }
}

