using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Server;
using Microsoft.AspNetCore.Components.Web;

namespace sv_e238e250037c4fe1a2c34232344b2095.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that simulates a logged-in user
/// and persists the auth state so the WebAssembly client can pick it up.
/// </summary>
public sealed class ServerAuthenticationStateProvider : ServerAuthenticationStateProvider<UserInfo>
{
    private static readonly ClaimsPrincipal _user = CreateUser();

    private static ClaimsPrincipal CreateUser()
    {
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, "bob@example.com"),
            new(ClaimTypes.Email, "bob@example.com"),
            new(ClaimTypes.Role, "User"),
            new(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        return new ClaimsPrincipal(identity);
    }

    protected override Task<AuthenticationState> GetAuthenticationStateAsync(
        IComponentRenderMode? renderMode)
    {
        return Task.FromResult(new AuthenticationState(_user));
    }

    protected override UserInfo MapToSerialized(AuthenticationState authenticationState)
    {
        var principal = authenticationState.User;
        return new UserInfo
        {
            Email = principal.FindFirstValue(ClaimTypes.Email) ?? "",
            Roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray()
        };
    }
}

