using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;

namespace sv_e238e250037c4fe1a2c34232344b2095.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that returns a hardcoded user
/// and persists the auth state into PersistentComponentState so
/// the WebAssembly client can restore it after the runtime takes over.
/// </summary>
public sealed class PersistingServerAuthStateProvider : AuthenticationStateProvider, IDisposable
{
    private static readonly Task<AuthenticationState> _authState = Task.FromResult(CreateState());
    private readonly PersistingComponentStateSubscription _subscription;

    public PersistingServerAuthStateProvider(PersistentComponentState persistentState)
    {
        _subscription = persistentState.RegisterOnPersisting(() =>
        {
            var state = _authState.Result;
            var principal = state.User;

            if (principal.Identity?.IsAuthenticated == true)
            {
                var userInfo = new UserInfo
                {
                    Email = principal.FindFirstValue(ClaimTypes.Email) ?? principal.Identity.Name ?? "",
                    Roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray()
                };

                persistentState.PersistAsJson(nameof(UserInfo), userInfo);
            }

            return Task.CompletedTask;
        }, RenderMode.InteractiveWebAssembly);
    }

    private static AuthenticationState CreateState()
    {
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, "bob@example.com"),
            new(ClaimTypes.Email, "bob@example.com"),
            new(ClaimTypes.Role, "User"),
            new(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        return new AuthenticationState(new ClaimsPrincipal(identity));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;

    public void Dispose() => _subscription.Dispose();
}

